/**
 * axiosClient.js
 * ─────────────────────────────────────────────────────────────
 * Cliente Axios preconfigurado para el backend.
 *
 * Interceptores:
 *   request  → adjunta el JWT en cada petición automáticamente
 *   response → redirige a /login si el servidor responde 401
 */

import axios from 'axios'

const axiosClient = axios.create({
  baseURL: 'http://localhost:4000/api',
  headers: { 'Content-Type': 'application/json' },
  timeout: 10000, // 10 segundos
})

// Adjunta el token JWT antes de cada petición
axiosClient.interceptors.request.use((config) => {
  const token = localStorage.getItem('finanzas_token')
  if (token) config.headers.Authorization = `Bearer ${token}`
  return config
})

// Manejo global de errores de autenticación
axiosClient.interceptors.response.use(
  (res) => res,
  (err) => {
    if (err.response?.status === 401) {
      localStorage.removeItem('finanzas_token')
      localStorage.removeItem('finanzas_user')
      window.location.href = '/login'
    }
    return Promise.reject(err)
  }
)

export default axiosClient
